```c++
#include <algorithm>

string reverseWords(string s) {
    string reversed_words;
    string word;

    for (char c : s) {
        if (c == ' ') {
            reversed_words += word + ' ';
            word = "";
        } else {
            word += c;
        }
    }
    reversed_words += word;
    return reversed_words;
}
```

